import { useState, useEffect } from 'react';
import { useQuery, gql } from '@apollo/client';

const GET_FILTERED_PRODUCTS = gql`
  query GetFilteredProducts($category: [String], $minPrice: Float, $maxPrice: Float, $minRating: Float) {
    products(
      filter: {
        category: $category,
        minPrice: $minPrice,
        maxPrice: $maxPrice,
        minRating: $minRating
      }
    ) {
      id
      name
      price
      category
      rating
      image
    }
  }
`;

const GET_CATEGORIES = gql`
  query GetCategories {
    categories {
      name
    }
  }
`;

export default function ProductFilter() {
  const [filters, setFilters] = useState({
    category: [],
    minPrice: 0,
    maxPrice: 1000,
    minRating: 0
  });

  const { loading: categoriesLoading, data: categoriesData } = useQuery(GET_CATEGORIES);

  const { loading, error, data } = useQuery(GET_FILTERED_PRODUCTS, {
    variables: filters
  });

  const handleCategoryChange = (e) => {
    const { value, checked } = e.target;
    setFilters(prev => ({
      ...prev,
      category: checked 
        ? [...prev.category, value]
        : prev.category.filter(cat => cat !== value)
    }));
  };

  const handlePriceChange = (e) => {
    const { name, value } = e.target;
    setFilters(prev => ({
      ...prev,
      [name]: parseFloat(value)
    }));
  };

  const handleRatingChange = (e) => {
    setFilters(prev => ({
      ...prev,
      minRating: parseFloat(e.target.value)
    }));
  };

  return (
    <div className="product-filter">
      <div className="filter-section">
        <h3>Categories</h3>
        {categoriesLoading ? (
          <p>Loading categories...</p>
        ) : (
          categoriesData?.categories.map(category => (
            <label key={category.name} className="category-checkbox">
              <input
                type="checkbox"
                value={category.name}
                onChange={handleCategoryChange}
                checked={filters.category.includes(category.name)}
              />
              {category.name}
            </label>
          ))
        )}
      </div>

      <div className="filter-section">
        <h3>Price Range</h3>
        <div className="price-inputs">
          <input
            type="number"
            name="minPrice"
            value={filters.minPrice}
            onChange={handlePriceChange}
            min="0"
          />
          <span>to</span>
          <input
            type="number"
            name="maxPrice"
            value={filters.maxPrice}
            onChange={handlePriceChange}
            min={filters.minPrice}
          />
        </div>
      </div>

      <div className="filter-section">
        <h3>Rating</h3>
        <input
          type="range"
          min="0"
          max="5"
          step="0.5"
          value={filters.minRating}
          onChange={handleRatingChange}
        />
        <span>{filters.minRating}+ stars</span>
      </div>

      <div className="products-container">
        {loading ? (
          <p>Loading products...</p>
        ) : error ? (
          <p>Error loading products: {error.message}</p>
        ) : data?.products.length === 0 ? (
          <p>No products match your selected filters.</p>
        ) : (
          data?.products.map(product => (
            <div key={product.id} className="product-card">
              <img src={product.image} alt={product.name} />
              <h4>{product.name}</h4>
              <p>${product.price.toFixed(2)}</p>
              <p>Rating: {product.rating}/5</p>
            </div>
          ))
        )}
      </div>
    </div>
  );
}
