      type: Object,
      default: null
    }
  },
  data() {
    return {
      valid: false,
      dateMenu: false,
      task: {
        id: null,
        title: '',
        description: '',
        priority: 'Medium',
        deadline: new Date().toISOString().substr(0, 10)
      },
      titleRules: [
        v => !!v || 'Title is required'
      ],
      dateRules: [
        v => !!v || 'Deadline is required'
      ],
      priorities: ['High', 'Medium', 'Low']
    };
  },
  computed: {
    isEditing() {
      return !!this.task.id;
    },
    formattedDate() {
      if (!this.task.deadline) return '';
      return format(new Date(this.task.deadline), 'MMMM dd, yyyy');
    }
  },
  watch: {
    taskToEdit(newTask) {
      if (newTask) {
        this.task = { ...newTask };
      } else {
        this.resetForm();
      }
    }
  },
  methods: {
    saveTask() {
      if (this.$refs.form.validate()) {
        if (this.isEditing) {
          this.$store.dispatch('updateTask', { ...this.task });
        } else {
          this.$store.dispatch('addTask', { 
            ...this.task, 
            id: Date.now().toString() 
          });
        }
        this.resetForm();
      }
    },
    resetForm() {
      this.$refs.form.reset();
      this.task = {
        id: null,
        title: '',
        description: '',
        priority: 'Medium',
        deadline: new Date().toISOString().substr(0, 10)
      };
      this.$emit('resetEdit');
    }
  }
};
