<script>
import { mapGetters } from 'vuex';

export default {
  name: 'TaskCalendar',
  data() {
    return {
      focus: new Date().toISOString().substr(0, 10),
      selectedEvent: {},
      selectedElement: null,
      selectedOpen: false,
      dragEvent: null,
      dragStart: null,
      dragEnd: null,
    };
  },
  computed: {
    ...mapGetters(['tasks']),
    calendarEvents() {
      return this.tasks.map(task => ({
        name: task.title,
        start: new Date(task.deadline),
        end: new Date(task.deadline),
        color: this.getPriorityColor(task.priority),
        timed: false,
        details: task.description,
        priority: task.priority,
        taskId: task.id
      }));
    },
  },
  mounted() {
    this.$refs.calendar.checkChange();
  },
  methods: {
    getPriorityColor(priority) {
      switch (priority) {
        case 'High': return 'red';
        case 'Medium': return 'orange';
        case 'Low': return 'green';
        default: return 'blue';
      }
    },
    getEventColor(event) {
      return event.color;
    },
    showEvent({ nativeEvent, event }) {
      const open = () => {
        this.selectedEvent = event;
        this.selectedElement = nativeEvent.target;
        setTimeout(() => {
          this.selectedOpen = true;
        }, 10);
      };

      if (this.selectedOpen) {
        this.selectedOpen = false;
        setTimeout(open, 10);
      } else {
        open();
      }

      nativeEvent.stopPropagation();
    },
    viewDay({ date }) {
      this.focus = date;
    },
    updateRange() {
      // This method would be used if we needed to fetch events for a specific date range
    },
    startDrag({ event, timed }) {
      if (event && timed) {
        this.dragEvent = event;
        this.dragTime = null;
        this.dragStart = null;
        this.dragEnd = null;
      }
    },
    extendDrag({ newStartTime, newEndTime }) {
      const { start, end } = this.dragEvent;
      this.dragStart = start;
      this.dragEnd = end;
      this.dragEvent.start = newStartTime;
      this.dragEvent.end = newEndTime;
    },
    endDrag() {
      // Update the task deadline when drag ends
      if (this.dragEvent && this.dragEvent.taskId) {
        const newDeadline = this.dragEvent.start.toISOString().substr(0, 10);
        this.$emit('updateTaskDate', {
          id: this.dragEvent.taskId,
          deadline: newDeadline
        });
      }
      this.dragStart = null;
      this.dragEnd = null;
      this.dragEvent = null;
    }
  }
};
</script>
