<?php
/**
 * Plugin Name: AJAX Product Search
 * Description: Adds AJAX-powered search functionality for WooCommerce products
 * Version: 1.0.0
 * Author: Your Name
 */

// Exit if accessed directly
if (!defined('ABSPATH')) {
    exit;
}

class AJAX_Product_Search {

    public function __construct() {
        // Enqueue scripts
        add_action('wp_enqueue_scripts', array($this, 'enqueue_scripts'));

        // Register AJAX handlers
        add_action('wp_ajax_filter_products', array($this, 'filter_products'));
        add_action('wp_ajax_nopriv_filter_products', array($this, 'filter_products'));

        // Add shortcode for search form
        add_shortcode('product_search_form', array($this, 'render_search_form'));
    }

    public function enqueue_scripts() {
        if (is_shop() || is_product_category() || is_front_page() || is_page()) {
            wp_enqueue_script(
                'ajax-product-search',
                plugin_dir_url(__FILE__) . 'js/product-search.js',
                array('jquery'),
                '1.0.0',
                true
            );

            wp_localize_script(
                'ajax-product-search',
                'ajax_product_search',
                array(
                    'ajax_url' => admin_url('admin-ajax.php'),
                    'nonce' => wp_create_nonce('product_search_nonce')
                )
            );
        }
    }

    public function filter_products() {
        // Verify nonce
        check_ajax_referer('product_search_nonce', 'security');

        $search_term = sanitize_text_field($_POST['search_term']);

        // Create new WP_Query
        $args = array(
            'post_type' => 'product',
            'post_status' => 'publish',
            'posts_per_page' => 12,
            's' => $search_term,
            'meta_query' => array(
                array(
                    'key' => '_stock_status',
                    'value' => 'instock',
                    'compare' => '='
                )
            )
        );

        $query = new WP_Query($args);

        ob_start();

        if ($query->have_posts()) {
            echo '<div class="products columns-4">';
            while ($query->have_posts()) {
                $query->the_post();
                wc_get_template_part('content', 'product');
            }
            echo '</div>';
        } else {
            echo '<p>No products found matching your search criteria.</p>';
        }

        wp_reset_postdata();

        $html = ob_get_clean();

        wp_send_json_success($html);
    }

    public function render_search_form() {
        ob_start();
        ?>
        <div class="ajax-product-search-container">
            <input type="text" id="product-search-input" placeholder="Search products..." />
            <div id="product-results"></div>
        </div>
        <?php
        return ob_get_clean();
    }
}

// Initialize the plugin
new AJAX_Product_Search();
