@login_required
def evaluate_speech(request, word_id):
    if request.method == 'POST' and request.FILES.get('audio'):
        word = get_object_or_404(Word, id=word_id)
        audio_file = request.FILES['audio']

        # Process audio with the speech recognition API
        result = evaluate_pronunciation(audio_file, word.text)

        # Save the attempt
        attempt = PronunciationAttempt.objects.create(
            user=request.user,
            word=word,
            audio_recording=audio_file,
            score=result['score'],
            feedback=result['feedback']
        )

        return JsonResponse({
            'success': True,
            'score': result['score'],
            'feedback': result['feedback']
        })

    return JsonResponse({'success': False, 'error': 'Invalid request'})

@login_required
def user_progress(request):
    attempts = PronunciationAttempt.objects.filter(user=request.user)
    words = Word.objects.all()

    # Prepare data for progress tracking
    progress_data = {}
    for word in words:
        word_attempts = attempts.filter(word=word)
        if word_attempts.exists():
            scores = [attempt.score for attempt in word_attempts]
            progress_data[word.text] = {
                'attempts': len(scores),
                'average': sum(scores) / len(scores),
                'best': max(scores),
                'latest': scores[0],
                'history': list(reversed(scores))
            }

    return render(request, 'pronunciation/progress.html', {
        'progress_data': json.dumps(progress_data)
    })
