<script>
    let mediaRecorder;
    let audioChunks = [];
    const word_id = {{ word.id }};

    document.getElementById('listen').addEventListener('click', function() {
        const audio = new Audio("{{ word.audio_reference.url }}");
        audio.play();
    });

    document.getElementById('record').addEventListener('click', async function() {
        // Request microphone access
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        mediaRecorder = new MediaRecorder(stream);

        mediaRecorder.ondataavailable = (event) => {
            audioChunks.push(event.data);
        };

        mediaRecorder.onstop = sendAudioToServer;

        // Start recording
        audioChunks = [];
        mediaRecorder.start();

        // Update UI
        document.getElementById('record').disabled = true;
        document.getElementById('stop').disabled = false;
    });

    document.getElementById('stop').addEventListener('click', function() {
        if (mediaRecorder && mediaRecorder.state !== 'inactive') {
            mediaRecorder.stop();
        }

        // Update UI
        document.getElementById('record').disabled = false;
        document.getElementById('stop').disabled = true;
    });

    function sendAudioToServer() {
        const audioBlob = new Blob(audioChunks, { type: 'audio/webm' });
        const formData = new FormData();
        formData.append('audio', audioBlob, 'recording.webm');

        fetch(`/pronunciation/evaluate/${word_id}/`, {
            method: 'POST',
            body: formData
        })
        .then(response => response.json())
        .then(data => {
            if (data.success) {
                // Display results
                const scoreBar = document.getElementById('score-bar');
                const scoreText = document.getElementById('score-text');
                const feedback = document.getElementById('feedback');

                scoreBar.style.width = `${data.score}%`;
                scoreText.textContent = `Score: ${data.score.toFixed(1)}%`;
                feedback.textContent = data.feedback;

                document.getElementById('result').classList.remove('d-none');
            } else {
                alert('Error: ' + data.error);
            }
        })
        .catch(error => {
            console.error('Error:', error);
            alert('An error occurred while evaluating your pronunciation.');
        });
    }
</script>
