      description: 'French dessert with caramelized sugar', 
      category: 'Desserts' 
    },
    { 
      id: 3, 
      name: 'Jalapeño Poppers', 
      description: 'Spicy appetizer', 
      category: 'Appetizers' 
    }
  ];

  describe('normalizeText', () => {
    it('should normalize accented characters', () => {
      expect(normalizeText('Café')).to.equal('cafe');
      expect(normalizeText('Crème')).to.equal('creme');
      expect(normalizeText('Jalapeño')).to.equal('jalapeno');
    });

    it('should handle empty or null input', () => {
      expect(normalizeText('')).to.equal('');
      expect(normalizeText(null)).to.equal('');
      expect(normalizeText(undefined)).to.equal('');
    });
  });

  describe('searchProducts', () => {
    it('should find products with exact match', () => {
      const result = searchProducts(products, { name: 'Café Espresso' });
      expect(result).to.have.lengthOf(1);
      expect(result[0].id).to.equal(1);
    });

    it('should find products with accent-insensitive search', () => {
      const result = searchProducts(products, { name: 'Cafe' });
      expect(result).to.have.lengthOf(1);
      expect(result[0].id).to.equal(1);
    });

    it('should find products with normalized search terms', () => {
      const result = searchProducts(products, { name: 'creme brulee' });
      expect(result).to.have.lengthOf(1);
      expect(result[0].id).to.equal(2);
