      expect(result[0].id).to.equal(2);
    });

    it('should handle empty products array', () => {
      expect(searchProducts([], { name: 'test' })).to.be.an('array').that.is.empty;
      expect(searchProducts(null, { name: 'test' })).to.be.an('array').that.is.empty;
