import { mapState, mapActions } from 'vuex';

export default {
  name: 'FriendRequest',

  data() {
    return {
      searchQuery: '',
      searchResults: []
    }
  },

  computed: {
    ...mapState({
      currentUser: state => state.auth.user,
      friends: state => state.friends.friends,
      outgoingRequests: state => state.friends.outgoingRequests,
      incomingRequests: state => state.friends.incomingRequests
    }),

    isFriend() {
      return (userId) => {
        return this.friends.some(friend => friend.id === userId);
      }
    },

    isPending() {
      return (userId) => {
        return this.outgoingRequests.some(request => request.receiver_id === userId);
      }
    }
  },

  methods: {
    ...mapActions('friends', [
      'fetchFriends',
      'fetchFriendRequests',
      'sendFriendRequest',
      'cancelFriendRequest',
      'acceptFriendRequest',
      'rejectFriendRequest',
      'removeFriendship'
    ]),

    async searchUsers() {
      if (this.searchQuery.length < 2) {
        this.searchResults = [];
        return;
