```js:store/modules/friends.js
import axios from 'axios';

export default {
  namespaced: true,

  state: {
    friends: [],
    outgoingRequests: [],
    incomingRequests: [],
    loading: false,
    error: null
  },

  mutations: {
    SET_LOADING(state, status) {
      state.loading = status;
    },

    SET_ERROR(state, error) {
      state.error = error;
    },

    SET_FRIENDS(state, friends) {
      state.friends = friends;
    },

    SET_OUTGOING_REQUESTS(state, requests) {
      state.outgoingRequests = requests;
    },

    SET_INCOMING_REQUESTS(state, requests) {
      state.incomingRequests = requests;
    },

    ADD_OUTGOING_REQUEST(state, request) {
      state.outgoingRequests.push(request);
    },

    REMOVE_OUTGOING_REQUEST(state, requestId) {
      state.outgoingRequests = state.outgoingRequests.filter(
        request => request.id !== requestId
      );
    },

    REMOVE_INCOMING_REQUEST(state, requestId) {
      state.incomingRequests = state.incomingRequests.filter(
        request => request.id !== requestId
      );
    },

    ADD_FRIEND(state, friend) {
      state.friends.push(friend);
    },

    REMOVE_FRIEND(state, friendId) {
      state.friends = state.friends.filter(friend => friend.id !== friendId);
    }
  },

  actions: {
    async fetchFriends({ commit }) {
      try {
        commit('SET_LOADING', true);
        const response = await axios.get('/api/friends');
        commit('SET_FRIENDS', response.data);
        commit('SET_LOADING', false);
      } catch (error) {
        commit('SET_ERROR', error.message);
        commit('SET_LOADING', false);
        throw error;
      }
    },

    async fetchFriendRequests({ commit }) {
      try {
        commit('SET_LOADING', true);
        const outgoing = await axios.get('/api/friend-requests/outgoing');
        const incoming = await axios.get('/api/friend-requests/incoming');

        commit('SET_OUTGOING_REQUESTS', outgoing.data);
        commit('SET_INCOMING_REQUESTS', incoming.data);
        commit('SET_LOADING', false);
      } catch (error) {
        commit('SET_ERROR', error.message);
        commit('SET_LOADING', false);
        throw error;
      }
    },

    async sendFriendRequest({ commit }, userId) {
      try {
        commit('SET_LOADING', true);
        const response = await axios.post('/api/friend-requests', { receiver_id: userId });
        commit('ADD_OUTGOING_REQUEST', response.data);
        commit('SET_LOADING', false);
        return response.data;
      } catch (error) {
        commit('SET_ERROR', error.message);
        commit('SET_LOADING', false);
        throw error;
      }
    },

    async cancelFriendRequest({ commit, state }, userId) {
      try {
        commit('SET_LOADING', true);
        const request = state.outgoingRequests.find(req => req.receiver_id === userId);
        if (request) {
          await axios.delete(`/api/friend-requests/${request.id}`);
          commit('REMOVE_OUTGOING_REQUEST', request.id);
        }
        commit('SET_LOADING', false);
      } catch (error) {
        commit('SET_ERROR', error.message);
        commit('SET_LOADING', false);
        throw error;
      }
    },

    async acceptFriendRequest({ commit }, requestId) {
      try {
        commit('SET_LOADING', true);
        const response = await axios.put(`/api/friend-requests/${requestId}/accept`);
        commit('REMOVE_INCOMING_REQUEST', requestId);
        commit('ADD_FRIEND', response.data.friend);
        commit('SET_LOADING', false);
      } catch (error) {
        commit('SET_ERROR', error.message);
        commit('SET_LOADING', false);
        throw error;
      }
    },

    async rejectFriendRequest({ commit }, requestId) {
      try {
        commit('SET_LOADING', true);
        await axios.put(`/api/friend-requests/${requestId}/reject`);
        commit('REMOVE_INCOMING_REQUEST', requestId);
        commit('SET_LOADING', false);
      } catch (error) {
        commit('SET_ERROR', error.message);
        commit('SET_LOADING', false);
        throw error;
      }
    },

    async removeFriendship({ commit }, friendId) {
      try {
        commit('SET_LOADING', true);
        await axios.delete(`/api/friends/${friendId}`);
        commit('REMOVE_FRIEND', friendId);
        commit('SET_LOADING', false);
      } catch (error) {
        commit('SET_ERROR', error.message);
        commit('SET_LOADING', false);
        throw error;
      }
    }
  },

  getters: {
    isLoading: state => state.loading,
    hasError: state => !!state.error,
    errorMessage: state => state.error,
    friendCount: state => state.friends.length,
    incomingRequestCount: state => state.incomingRequests.length
  }
}
