<?php

namespace App\Http\Middleware;

use Closure;
use Illuminate\Http\Request;
use App\Models\Language;

class DetectUserLanguage
{
    /**
     * Handle an incoming request.
     *
     * @param  \Illuminate\Http\Request  $request
     * @param  \Closure  $next
     * @return mixed
     */
    public function handle(Request $request, Closure $next)
    {
        $acceptLanguage = $request->header('Accept-Language');

        if ($acceptLanguage) {
            // Parse Accept-Language header
            $languages = explode(',', $acceptLanguage);
            $locales = [];

            foreach ($languages as $language) {
                $parts = explode(';', $language);
                $locale = trim($parts[0]);
                $locales[] = $locale;
            }

            // Get available languages from the database
            $availableLanguages = Language::where('is_active', true)
                ->pluck('code')
                ->toArray();

            // Find the first matching language
            foreach ($locales as $locale) {
                $shortLocale = substr($locale, 0, 2);

                if (in_array($locale, $availableLanguages)) {
                    app()->setLocale($locale);
                    break;
                } elseif (in_array($shortLocale, $availableLanguages)) {
                    app()->setLocale($shortLocale);
                    break;
                }
            }
        }

        return $next($request);
    }
}
