<?php
/**
 * Plugin Name: Secure File Upload Validator
 * Description: Enhances CMS security by validating file uploads based on type, size, and scanning for malware using ClamAV.
 * Version: 1.0.0
 * Author: Development Team
 */

// Exit if accessed directly
if (!defined('ABSPATH')) {
    exit;
}

class SecureFileUploadValidator {
    // Configuration parameters
    private $max_file_size = 10485760; // 10MB in bytes
    private $allowed_file_types = [
        'image/jpeg', 'image/png', 'image/gif',
        'application/pdf', 'application/msword',
        'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
        'text/plain', 'text/csv'
    ];
    private $clamav_socket = '/var/run/clamav/clamd.ctl';

    /**
     * Constructor - set up hooks
     */
    public function __construct() {
        // Hook into file upload validation
        add_filter('upload_validation_pre_process', [$this, 'validateUpload'], 10, 1);

        // Hook into admin initialization to add settings page
        add_action('admin_init', [$this, 'registerSettings']);
        add_action('admin_menu', [$this, 'addSettingsPage']);
    }

    /**
     * Validate uploaded file
     *
     * @param array $file The uploaded file information
     * @return array Modified file information with error if validation fails
     */
    public function validateUpload($file) {
        // Check file size
        if ($file['size'] > $this->max_file_size) {
            $file['error'] = sprintf(
                __('File size exceeds the maximum limit of %s MB.', 'secure-upload'),
                $this->max_file_size / 1048576
            );
            return $file;
        }

        // Check file type
        $file_type = $file['type'];
        if (!in_array($file_type, $this->allowed_file_types)) {
            $file['error'] = __('File type not allowed. Allowed types: JPEG, PNG, GIF, PDF, DOC, DOCX, TXT, CSV.', 'secure-upload');
            return $file;
        }

        // Scan for malware using ClamAV
        $scan_result = $this->scanForMalware($file['tmp_name']);
        if ($scan_result !== true) {
            $file['error'] = $scan_result;
            return $file;
        }

        return $file;
    }

    /**
     * Scan file for malware using ClamAV
     *
     * @param string $file_path Path to temporary uploaded file
     * @return bool|string True if clean, error message if infected or error
     */
    private function scanForMalware($file_path) {
        // Check if ClamAV is available
        if (!extension_loaded('sockets') || !file_exists($this->clamav_socket)) {
            // Log the error but allow upload to proceed
            error_log('ClamAV socket not available for malware scanning');
            return true;
        }

        try {
            $socket = socket_create(AF_UNIX, SOCK_STREAM, 0);
            if ($socket === false) {
                throw new Exception("Could not create socket");
            }

            $connection = socket_connect($socket, $this->clamav_socket);
            if ($connection === false) {
                throw new Exception("Could not connect to ClamAV socket");
            }

            // Prepare the scan command
            $scan_command = "SCAN " . $file_path . "\n";
            socket_write($socket, $scan_command, strlen($scan_command));

            // Read the response
            $response = socket_read($socket, 4096);
            socket_close($socket);

            // Parse response
            if (strpos($response, 'OK') !== false) {
                return true;
            } else if (strpos($response, 'FOUND') !== false) {
                return __('Security threat detected in the uploaded file. Upload rejected.', 'secure-upload');
            } else {
                return __('Error scanning file for security threats. Please try again later.', 'secure-upload');
            }
        } catch (Exception $e) {
            error_log('ClamAV scanning error: ' . $e->getMessage());
            // Allow upload to proceed if scanning fails
            return true;
        }
    }

    /**
     * Register plugin settings
     */
    public function registerSettings() {
        register_setting('secure_upload_settings', 'secure_upload_max_size');
        register_setting('secure_upload_settings', 'secure_upload_allowed_types');
        register_setting('secure_upload_settings', 'secure_upload_clamav_socket');

        add_settings_section(
            'secure_upload_section',
            __('Secure File Upload Settings', 'secure-upload'),
            [$this, 'settingsSectionCallback'],
            'secure-upload-settings'
        );

        add_settings_field(
            'secure_upload_max_size',
            __('Maximum File Size (MB)', 'secure-upload'),
            [$this, 'maxSizeFieldCallback'],
            'secure-upload-settings',
            'secure_upload_section'
        );

        add_settings_field(
            'secure_upload_allowed_types',
            __('Allowed File Types', 'secure-upload'),
            [$this, 'allowedTypesFieldCallback'],
            'secure-upload-settings',
            'secure_upload_section'
        );

        add_settings_field(
            'secure_upload_clamav_socket',
            __('ClamAV Socket Path', 'secure-upload'),
            [$this, 'clamavSocketFieldCallback'],
            'secure-upload-settings',
            'secure_upload_section'
        );
    }

    /**
     * Add settings page to admin menu
     */
    public function addSettingsPage() {
        add_options_page(
            __('Secure Upload Settings', 'secure-upload'),
            __('Secure Upload', 'secure-upload'),
            'manage_options',
            'secure-upload-settings',
            [$this, 'renderSettingsPage']
        );
    }

    /**
     * Settings section description
     */
    public function settingsSectionCallback() {
        echo '<p>' . __('Configure the secure file upload validation settings.', 'secure-upload') . '</p>';
    }

    /**
     * Maximum file size field callback
     */
    public function maxSizeFieldCallback() {
        $value = get_option('secure_upload_max_size', 10);
        echo '<input type="number" name="secure_upload_max_size" value="' . esc_attr($value) . '" min="1" max="100" />';
    }

    /**
     * Allowed file types field callback
     */
    public function allowedTypesFieldCallback() {
        $value = get_option('secure_upload_allowed_types', implode(',', $this->allowed_file_types));
        echo '<textarea name="secure_upload_allowed_types" rows="5" cols="50">' . esc_textarea($value) . '</textarea>';
        echo '<p class="description">' . __('Enter MIME types separated by commas.', 'secure-upload') . '</p>';
    }

    /**
     * ClamAV socket path field callback
     */
    public function clamavSocketFieldCallback() {
        $value = get_option('secure_upload_clamav_socket', $this->clamav_socket);
        echo '<input type="text" name="secure_upload_clamav_socket" value="' . esc_attr($value) . '" class="regular-text" />';
    }

    /**
     * Render settings page
     */
    public function renderSettingsPage() {
        if (!current_user_can('manage_options')) {
            return;
        }

        ?>
        <div class="wrap">
            <h1><?php echo esc_html(get_admin_page_title()); ?></h1>
            <form action="options.php" method="post">
                <?php
                settings_fields('secure_upload_settings');
                do_settings_sections('secure-upload-settings');
                submit_button();
                ?>
            </form>
        </div>
        <?php
    }

    /**
     * Load saved settings
     */
    public function loadSettings() {
        $this->max_file_size = get_option('secure_upload_max_size', 10) * 1048576; // Convert MB to bytes
        $saved_types = get_option('secure_upload_allowed_types', '');
        if (!empty($saved_types)) {
            $this->allowed_file_types = array_map('trim', explode(',', $saved_types));
        }
        $this->clamav_socket = get_option('secure_upload_clamav_socket', $this->clamav_socket);
    }
}

