  const userId = ctx.state.user.id;
  ctx.body = await webhookService.getAll(userId);
});

router.get('/:id', async (ctx) => {
  const userId = ctx.state.user.id;
  const webhook = await webhookService.getById(userId, ctx.params.id);

  if (!webhook) {
    ctx.status = 404;
    return;
  }

  ctx.body = webhook;
});

router.put('/:id', async (ctx) => {
  const userId = ctx.state.user.id;
  const webhook = await webhookService.update(userId, ctx.params.id, ctx.request.body);

  if (!webhook) {
    ctx.status = 404;
    return;
  }

  ctx.body = webhook;
});

router.delete('/:id', async (ctx) => {
  const userId = ctx.state.user.id;
  const webhook = await webhookService.delete(userId, ctx.params.id);

  if (!webhook) {
    ctx.status = 404;
    return;
  }

  ctx.status = 204;
});

module.exports = router;
