      </div>
      <div v-else class="product-card" v-for="product in filteredProducts" :key="product.id">
        <img :src="product.image" :alt="product.title">
        <h3>{{ product.title }}</h3>
        <p class="price">${{ product.price.toFixed(2) }}</p>
        <button @click="addToCart(product)" class="add-to-cart">Add to Cart</button>
      </div>
    </div>

    <div class="pagination">
      <button 
        :disabled="currentPage === 1" 
        @click="changePage(currentPage - 1)"
      >
        Previous
      </button>
      <span>Page {{ currentPage }} of {{ totalPages }}</span>
      <button 
        :disabled="currentPage === totalPages" 
        @click="changePage(currentPage + 1)"
      >
        Next
      </button>
    </div>
  </div>
</template>

<script>
import { mapState, mapActions } from 'vuex';

export default {
  name: 'ProductListing',
  data() {
    return {
      selectedCategory: null,
      currentPage: 1,
      productsPerPage: 8
    };
  },
  computed: {
    ...mapState({
      products: state => state.products.items,
      categories: state => state.categories.items,
      loading: state => state.products.loading
    }),
    filteredProducts() {
      let filtered = this.selectedCategory === null
        ? [...this.products]
        : this.products.filter(product => product.categoryId === this.selectedCategory);

      // Apply pagination
      const startIndex = (this.currentPage - 1) * this.productsPerPage;
      const endIndex = startIndex + this.productsPerPage;
      return filtered.slice(startIndex, endIndex);
    },
    totalPages() {
      const filtered = this.selectedCategory === null
        ? this.products
        : this.products.filter(product => product.categoryId === this.selectedCategory);
      return Math.ceil(filtered.length / this.productsPerPage);
    }
  },
  methods: {
    ...mapActions({
      fetchProducts: 'products/fetchProducts',
      fetchCategories: 'categories/fetchCategories',
      addProductToCart: 'cart/addItem'
    }),
    filterByCategory(categoryId) {
      this.selectedCategory = categoryId;
      this.currentPage = 1;
    },
    changePage(page) {
      this.currentPage = page;
    },
    addToCart(product) {
      this.addProductToCart(product);
    }
  },
  created() {
    this.fetchProducts();
    this.fetchCategories();
  }
};
</script>

