```typescript:src/payments/payments.service.ts
import { Injectable, Logger, BadRequestException, ServiceUnavailableException } from '@nestjs/common';
import { InjectModel } from '@nestjs/mongoose';
import { Model, Connection } from 'mongoose';
import { InjectConnection } from '@nestjs/mongoose';
import Stripe from 'stripe';
import { ConfigService } from '@nestjs/config';
import { Payment, PaymentDocument } from './schemas/payment.schema';
import { CreatePaymentDto } from './dto/create-payment.dto';

@Injectable()
export class PaymentsService {
  private readonly stripe: Stripe;
  private readonly logger = new Logger(PaymentsService.name);

  constructor(
    @InjectModel(Payment.name) private paymentModel: Model<PaymentDocument>,
    @InjectConnection() private connection: Connection,
    private configService: ConfigService,
  ) {
    this.stripe = new Stripe(this.configService.get<string>('STRIPE_SECRET_KEY'), {
      apiVersion: '2023-10-16',
    });
  }

  async createPayment(createPaymentDto: CreatePaymentDto) {
    const session = await this.connection.startSession();
    session.startTransaction();

    try {
      // Create payment document
      const newPayment = new this.paymentModel(createPaymentDto);
      await newPayment.save({ session });

      // Create Stripe PaymentIntent
      const paymentIntent = await this.stripe.paymentIntents.create({
        amount: Math.round(createPaymentDto.amount * 100), // Convert to cents
        currency: createPaymentDto.currency.toLowerCase(),
        metadata: {
          customerId: createPaymentDto.customerId,
          paymentId: newPayment._id.toString(),
        },
      });

      // Update payment with Stripe PaymentIntent ID
      newPayment.stripePaymentIntentId = paymentIntent.id;
      await newPayment.save({ session });

      await session.commitTransaction();

      return {
        paymentId: newPayment._id,
        clientSecret: paymentIntent.client_secret,
      };
    } catch (error) {
      await session.abortTransaction();

      this.logger.error({
        message: 'Payment processing failed',
        error: error.message,
        stack: error.stack,
        data: createPaymentDto,
      });

      throw new ServiceUnavailableException({
        error: 'Payment gateway error',
        details: error.message,
      });
    } finally {
      session.endSession();
    }
  }
}
