from flask import Flask, request, jsonify
from flask_pymongo import PyMongo
from bson.objectid import ObjectId
from functools import wraps
import jwt
import os
from datetime import datetime, timedelta

app = Flask(__name__)
app.config["MONGO_URI"] = os.environ.get("MONGO_URI", "mongodb://localhost:27017/health_system")
app.config["SECRET_KEY"] = os.environ.get("SECRET_KEY", "your-secret-key")
mongo = PyMongo(app)

# Pre-defined health conditions
VALID_CONDITIONS = [
    "Hypertension", "Diabetes", "Asthma", "Arthritis", "Depression", 
    "Anxiety", "COPD", "Cancer", "Heart Disease", "Obesity"
]

def token_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get('Authorization')
        if not token:
            return jsonify({'message': 'Token is missing!'}), 401

        try:
            token = token.split(" ")[1]
            data = jwt.decode(token, app.config['SECRET_KEY'], algorithms=["HS256"])
            current_user = mongo.db.users.find_one({'_id': ObjectId(data['user_id'])})
        except:
            return jsonify({'message': 'Token is invalid!'}), 401

        return f(current_user, *args, **kwargs)
    return decorated

@app.route('/patient/<patient_id>', methods=['PUT'])
@token_required
def update_patient(current_user, patient_id):
    try:
        data = request.get_json()

        # Validate required fields
        if not all(key in data for key in ['name', 'age', 'conditions']):
            return jsonify({'error': 'Missing required fields'}), 400

        # Validate data types
        if not isinstance(data['name'], str):
            return jsonify({'error': 'Name must be a string'}), 400

        if not isinstance(data['age'], int):
            return jsonify({'error': 'Age must be an integer'}), 400

        if data['age'] < 0:
            return jsonify({'error': 'Age must be non-negative'}), 400

        if not isinstance(data['conditions'], list):
            return jsonify({'error': 'Conditions must be a list'}), 400

        # Validate conditions
        invalid_conditions = [c for c in data['conditions'] if c not in VALID_CONDITIONS]
        if invalid_conditions:
            return jsonify({'error': f'Invalid conditions: {", ".join(invalid_conditions)}'}), 400

        # Update patient record
        result = mongo.db.patients.update_one(
            {'_id': ObjectId(patient_id)},
            {'$set': {
                'name': data['name'],
                'age': data['age'],
                'conditions': data['conditions'],
                'updated_at': datetime.utcnow()
            }}
        )

        if result.matched_count == 0:
            return jsonify({'error': 'Patient not found'}), 404

        # Get updated patient data
        updated_patient = mongo.db.patients.find_one({'_id': ObjectId(patient_id)})
        updated_patient['_id'] = str(updated_patient['_id'])
        updated_patient['updated_at'] = updated_patient['updated_at'].isoformat()

        return jsonify(updated_patient), 200

    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=False)
