      <h4>Price Range: ${{ priceRange[0] }} - ${{ priceRange[1] }}</h4>
      <div class="slider-container">
        <input 
          type="range" 
          v-model.number="priceRange[0]" 
          :min="minPrice" 
          :max="maxPrice" 
          @change="applyFilters"
        >
        <input 
          type="range" 
          v-model.number="priceRange[1]" 
          :min="minPrice" 
          :max="maxPrice" 
          @change="applyFilters"
        >
      </div>
    </div>

    <!-- Clear Filters Button -->
    <button @click="clearFilters" class="clear-filters-btn">Clear All Filters</button>
  </div>
</template>

<script>
import { mapState, mapActions } from 'vuex';

export default {
  name: 'ProductFilter',

  data() {
    return {
      selectedBrands: [],
      selectedRatings: [],
      priceRange: [0, 1000]
    };
  },

  computed: {
    ...mapState({
      brands: state => state.products.availableBrands,
      ratings: state => state.products.availableRatings,
      minPrice: state => state.products.priceRange.min,
      maxPrice: state => state.products.priceRange.max
    })
  },

  methods: {
    ...mapActions('products', [
      'fetchProducts',
      'updateFilters'
    ]),

    applyFilters() {
      this.updateFilters({
        brands: this.selectedBrands,
        ratings: this.selectedRatings,
        priceRange: this.priceRange
      });
    },

    clearFilters() {
      this.selectedBrands = [];
      this.selectedRatings = [];
      this.priceRange = [this.minPrice, this.maxPrice];
      this.applyFilters();
    }
  },

  created() {
    // Initialize price range from store on component creation
    this.priceRange = [this.minPrice, this.maxPrice];
    // Fetch initial products data
    this.fetchProducts();
  }
}
</script>

