    commit('APPLY_FILTERS');
  },

  updateFilters({ commit }, filters) {
    commit('SET_ACTIVE_FILTERS', filters);
    commit('APPLY_FILTERS');
  }
};

const mutations = {
  SET_PRODUCTS(state, products) {
    state.products = products;
    state.filteredProducts = products;
  },

  SET_ACTIVE_FILTERS(state, filters) {
    state.activeFilters = {
      ...state.activeFilters,
      ...filters
    };
  },

  APPLY_FILTERS(state) {
    const { brands, ratings, priceRange } = state.activeFilters;

    state.filteredProducts = state.products.filter(product => {
      // Filter by brand if any brands are selected
      const brandMatch = brands.length === 0 || brands.includes(product.brand);

      // Filter by rating if any ratings are selected
      const ratingMatch = ratings.length === 0 || ratings.some(rating => product.rating >= rating);

      // Filter by price range
      const priceMatch = product.price >= priceRange[0] && product.price <= priceRange[1];

      return brandMatch && ratingMatch && priceMatch;
    });
  }
};

export default {
  namespaced: true,
  state,
  getters,
  actions,
  mutations
};
