public class ScoreManager : MonoBehaviour
{
    [Header("Score Values")]
    [SerializeField] private int pointsPerItem = 10;
    [SerializeField] private int pointsPerEnemy = 25;
    [SerializeField] private int pointsPerLevel = 100;

    [Header("UI References")]
    [SerializeField] private Text scoreText;
    [SerializeField] private Text highScoreText;

    private int currentScore = 0;
    private int highScore = 0;
    private const string HIGH_SCORE_KEY = "HighScore";

    private void Start()
    {
        LoadHighScore();
        UpdateScoreUI();
    }

    public void AddItemPoints()
    {
        UpdateScore(pointsPerItem);
    }

    public void AddEnemyPoints()
    {
        UpdateScore(pointsPerEnemy);
    }

    public void AddLevelPoints()
    {
        UpdateScore(pointsPerLevel);
    }

    private void UpdateScore(int points)
    {
        currentScore += points;

        if (currentScore > highScore)
        {
            highScore = currentScore;
            SaveHighScore();
        }

        UpdateScoreUI();
    }

    private void UpdateScoreUI()
    {
        if (scoreText != null)
            scoreText.text = "Score: " + currentScore.ToString();

        if (highScoreText != null)
            highScoreText.text = "High Score: " + highScore.ToString();
    }

    private void SaveHighScore()
    {
        PlayerPrefs.SetInt(HIGH_SCORE_KEY, highScore);
        PlayerPrefs.Save();
    }

    private void LoadHighScore()
    {
        highScore = PlayerPrefs.GetInt(HIGH_SCORE_KEY, 0);
    }

    public void ResetScore()
    {
        currentScore = 0;
        UpdateScoreUI();
    }

    public int GetCurrentScore()
    {
        return currentScore;
    }
}
