Here's the implementation of a rate limiting and IP blocking middleware for Express.js to mitigate DDoS attacks:

```javascript:src/middleware/rateLimiter.js
const redis = require('redis');
const { promisify } = require('util');
const winston = require('winston');
const ipRangeCheck = require('ip-range-check');

class RateLimiterMiddleware {
  constructor(options = {}) {
    this.options = {
      // Default window size: 15 minutes
      windowMs: options.windowMs || 15 * 60 * 1000, 
      // Default max requests per window
      maxRequests: options.maxRequests || 100,
      // Default block duration: 1 hour
      blockDuration: options.blockDuration || 60 * 60 * 1000,
      // Redis connection options
      redisOptions: options.redisOptions || { url: process.env.REDIS_URL || 'redis://localhost:6379' },
      // Whitelist of IPs or IP ranges that won't be rate limited
      whitelistedIPs: options.whitelistedIPs || [],
      // Logging options
      logLevel: options.logLevel || 'info'
    };

    // Set up Redis client
    this.redisClient = redis.createClient(this.options.redisOptions);
    this.redisClient.on('error', (err) => {
      console.error('Redis error:', err);
    });

    // Promisify Redis methods
    this.getAsync = promisify(this.redisClient.get).bind(this.redisClient);
    this.setAsync = promisify(this.redisClient.set).bind(this.redisClient);
    this.incrAsync = promisify(this.redisClient.incr).bind(this.redisClient);
    this.expireAsync = promisify(this.redisClient.expire).bind(this.redisClient);
    this.delAsync = promisify(this.redisClient.del).bind(this.redisClient);
    this.keysAsync = promisify(this.redisClient.keys).bind(this.redisClient);

    // Set up logger
    this.logger = winston.createLogger({
      level: this.options.logLevel,
      format: winston.format.combine(
        winston.format.timestamp(),
        winston.format.json()
      ),
      transports: [
        new winston.transports.File({ filename: 'rate-limiter.log' }),
        new winston.transports.Console()
      ]
    });
  }

  // Method to check if an IP is whitelisted
  isWhitelisted(ip) {
    return this.options.whitelistedIPs.some(whitelistedIP => 
      ipRangeCheck(ip, whitelistedIP));
  }

  // Rate limiting middleware
  middleware() {
    return async (req, res, next) => {
      const ip = req.ip || req.connection.remoteAddress;

      // Skip rate limiting for whitelisted IPs
      if (this.isWhitelisted(ip)) {
        return next();
      }

      const requestKey = `request:${ip}`;
      const blockedKey = `blocked:${ip}`;

      try {
        // Check if IP is blocked
        const isBlocked = await this.getAsync(blockedKey);
        if (isBlocked) {
          this.logger.info(`Blocked request from banned IP: ${ip}`);
          return res.status(429).json({
            error: 'Too many requests. Your IP has been temporarily blocked.'
          });
        }

        // Increment request count
        const requestCount = await this.incrAsync(requestKey);

        // Set expiry on first request
        if (requestCount === 1) {
          await this.expireAsync(requestKey, Math.floor(this.options.windowMs / 1000));
        }

        // Check if request count exceeds threshold
        if (requestCount > this.options.maxRequests) {
          // Block the IP
          await this.setAsync(blockedKey, Date.now().toString());
          await this.expireAsync(blockedKey, Math.floor(this.options.blockDuration / 1000));

          // Log the blocked IP
          this.logger.warn({
            message: `IP blocked due to rate limit exceeded`,
            ip,
            requestCount,
            timestamp: new Date().toISOString()
          });

          return res.status(429).json({
            error: 'Too many requests. Your IP has been temporarily blocked.'
          });
        }

        // If we get here, request is allowed
        next();
      } catch (err) {
        this.logger.error(`Rate limiter error: ${err.message}`);
        // Fail open - let the request through if the rate limiter fails
        next();
      }
    };
  }

  // Admin methods for managing blocked IPs
  async getBlockedIPs() {
    try {
      const keys = await this.keysAsync('blocked:*');
      const blockedIPs = [];

      for (const key of keys) {
        const ip = key.replace('blocked:', '');
        const timestamp = await this.getAsync(key);
        blockedIPs.push({
          ip,
          blockedAt: new Date(parseInt(timestamp)),
          expiresAt: new Date(parseInt(timestamp) + this.options.blockDuration)
        });
      }

      return blockedIPs;
    } catch (err) {
      this.logger.error(`Error fetching blocked IPs: ${err.message}`);
      throw err;
    }
  }

  async unblockIP(ip) {
    try {
      await this.delAsync(`blocked:${ip}`);
      this.logger.info(`IP ${ip} has been manually unblocked`);
      return true;
    } catch (err) {
      this.logger.error(`Error unblocking IP ${ip}: ${err.message}`);
      throw err;
    }
  }

  async manuallyBlockIP(ip, duration = null) {
    try {
      const blockDuration = duration || this.options.blockDuration;
      await this.setAsync(`blocked:${ip}`, Date.now().toString());
      await this.expireAsync(`blocked:${ip}`, Math.floor(blockDuration / 1000));

      this.logger.info({
        message: `IP ${ip} has been manually blocked`,
        ip,
        duration: blockDuration,
        timestamp: new Date().toISOString()
      });

      return true;
    } catch (err) {
      this.logger.error(`Error blocking IP ${ip}: ${err.message}`);
      throw err;
    }
  }
}

module.exports = RateLimiterMiddleware;
