package com.retail.fulfillment.service;

import com.retail.fulfillment.dto.FulfillmentItemDTO;
import com.retail.fulfillment.dto.FulfillmentRequestDTO;
import com.retail.fulfillment.model.FulfillmentItem;
import com.retail.fulfillment.model.FulfillmentRequest;
import com.retail.fulfillment.repository.FulfillmentRepository;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.retry.annotation.Backoff;
import org.springframework.retry.annotation.Retryable;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.stream.Collectors;

@Service
@Slf4j
@RequiredArgsConstructor
public class FulfillmentService {

    private final FulfillmentRepository fulfillmentRepository;
    private final KafkaTemplate<String, FulfillmentRequest> kafkaTemplate;
    private static final String FULFILLMENT_TOPIC = "fulfillment.requested";

    @Transactional
    @Retryable(value = {Exception.class}, maxAttempts = 3, 
               backoff = @Backoff(delay = 1000, multiplier = 2))
    public FulfillmentRequest createFulfillment(FulfillmentRequestDTO requestDTO) {
        log.info("Creating fulfillment request for order: {}", requestDTO.getOrderId());

        FulfillmentRequest fulfillmentRequest = new FulfillmentRequest();
        fulfillmentRequest.setOrderId(requestDTO.getOrderId());
        fulfillmentRequest.setWarehouseId(requestDTO.getWarehouseId());
        fulfillmentRequest.setRequestedShipDate(requestDTO.getRequestedShipDate());

        // Save the fulfillment request first to get an ID
        FulfillmentRequest savedRequest = fulfillmentRepository.save(fulfillmentRequest);

        // Map and associate items with the saved request
        savedRequest.setItems(requestDTO.getItems().stream()
            .map(itemDTO -> mapToFulfillmentItem(itemDTO, savedRequest))
            .collect(Collectors.toList()));

        // Save again with items
        FulfillmentRequest result = fulfillmentRepository.save(savedRequest);

        // Publish event to Kafka
        publishFulfillmentRequestedEvent(result);

        return result;
    }

    private FulfillmentItem mapToFulfillmentItem(FulfillmentItemDTO itemDTO, FulfillmentRequest request) {
        FulfillmentItem item = new FulfillmentItem();
        item.setProductId(itemDTO.getProductId());
        item.setQuantity(itemDTO.getQuantity());
        item.setFulfillmentRequest(request);
        return item;
    }

    @Retryable(value = {Exception.class}, maxAttempts = 3, 
               backoff = @Backoff(delay = 1000, multiplier = 2))
    public void publishFulfillmentRequestedEvent(FulfillmentRequest fulfillmentRequest) {
        log.info("Publishing fulfillment.requested event for fulfillment ID: {}", fulfillmentRequest.getId());
        kafkaTemplate.send(FULFILLMENT_TOPIC, fulfillmentRequest.getId().toString(), fulfillmentRequest);
    }
}
