using System;
using System.ComponentModel.DataAnnotations;
using System.Net.Http;
using System.Text.Json;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Caching.Memory;
using Microsoft.Extensions.Logging;
using CurrencyConversionService.Models;
using CurrencyConversionService.Services;
using Microsoft.Extensions.Options;

namespace CurrencyConversionService.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    [Produces("application/json")]
    public class ConversionController : ControllerBase
    {
        private readonly IExchangeRateService _exchangeRateService;
        private readonly ILogger<ConversionController> _logger;
        private readonly IApiKeyValidator _apiKeyValidator;

        public ConversionController(
            IExchangeRateService exchangeRateService,
            ILogger<ConversionController> logger,
            IApiKeyValidator apiKeyValidator)
        {
            _exchangeRateService = exchangeRateService ?? throw new ArgumentNullException(nameof(exchangeRateService));
            _logger = logger ?? throw new ArgumentNullException(nameof(logger));
            _apiKeyValidator = apiKeyValidator ?? throw new ArgumentNullException(nameof(apiKeyValidator));
        }

        /// <summary>
        /// Converts an amount from one currency to another using real-time exchange rates
        /// </summary>
        /// <param name="request">The conversion request parameters</param>
        /// <returns>The conversion result</returns>
        /// <response code="200">Returns the conversion result</response>
        /// <response code="400">If the request parameters are invalid</response>
        /// <response code="401">If the API key is missing or invalid</response>
        /// <response code="503">If the exchange rate service is unavailable</response>
        [HttpGet("convert")]
        [ProducesResponseType(typeof(ConversionResult), StatusCodes.Status200OK)]
        [ProducesResponseType(typeof(ErrorResponse), StatusCodes.Status400BadRequest)]
        [ProducesResponseType(typeof(ErrorResponse), StatusCodes.Status401Unauthorized)]
        [ProducesResponseType(typeof(ErrorResponse), StatusCodes.Status503ServiceUnavailable)]
        public async Task<IActionResult> Convert([FromQuery] ConversionRequest request)
        {
            string correlationId = Guid.NewGuid().ToString();
            HttpContext.Response.Headers.Add("X-Correlation-Id", correlationId);

            _logger.LogInformation(
                JsonSerializer.Serialize(new
                {
                    CorrelationId = correlationId,
                    Operation = "ConvertCurrency",
                    Request = request
                }));

            // API key validation
            string apiKey = Request.Headers["X-Api-Key"];
            if (string.IsNullOrEmpty(apiKey) || !_apiKeyValidator.IsValid(apiKey))
            {
                var unauthorized = new ErrorResponse
                {
                    Error = "Unauthorized",
                    Details = "Missing or invalid API key"
                };

                _logger.LogWarning(
                    JsonSerializer.Serialize(new
                    {
                        CorrelationId = correlationId,
                        Operation = "ConvertCurrency",
                        Status = StatusCodes.Status401Unauthorized,
                        Message = "Unauthorized access attempt"
                    }));

                return Unauthorized(unauthorized);
            }

            // Model validation is handled by [ApiController]
            if (!ModelState.IsValid)
            {
                return BadRequest(new ErrorResponse
                {
                    Error = "Validation failed",
                    Details = ModelState
                });
            }

            try
            {
                var rate = await _exchangeRateService.GetExchangeRateAsync(
                    request.FromCurrency,
                    request.ToCurrency);

                var result = new ConversionResult
                {
                    FromCurrency = request.FromCurrency,
                    ToCurrency = request.ToCurrency,
                    ExchangeRate = rate,
                    OriginalAmount = request.Amount,
                    ConvertedAmount = request.Amount * rate,
                    Timestamp = DateTime.UtcNow
                };

                _logger.LogInformation(
                    JsonSerializer.Serialize(new
                    {
                        CorrelationId = correlationId,
                        Operation = "ConvertCurrency",
                        Status = StatusCodes.Status200OK,
                        Result = result
                    }));

                return Ok(result);
            }
            catch (ExchangeRateServiceException ex)
            {
                var serviceUnavailable = new ErrorResponse
                {
                    Error = "Rate service unavailable",
                    Details = ex.Message
                };

                _logger.LogError(ex,
                    JsonSerializer.Serialize(new
                    {
                        CorrelationId = correlationId,
                        Operation = "ConvertCurrency",
                        Status = StatusCodes.Status503ServiceUnavailable,
                        Exception = ex.Message
                    }));

                return StatusCode(StatusCodes.Status503ServiceUnavailable, serviceUnavailable);
            }
        }
    }
}
