using System;
using System.Net.Http;
using System.Text.Json;
using System.Threading.Tasks;
using Microsoft.Extensions.Caching.Memory;
using Microsoft.Extensions.Logging;
using Microsoft.Extensions.Options;

namespace CurrencyConversionService.Services
{
    public class ExchangeRateService : IExchangeRateService
    {
        private readonly IHttpClientFactory _httpClientFactory;
        private readonly IMemoryCache _memoryCache;
        private readonly ILogger<ExchangeRateService> _logger;
        private readonly ExchangeRateServiceOptions _options;

        public ExchangeRateService(
            IHttpClientFactory httpClientFactory,
            IMemoryCache memoryCache,
            ILogger<ExchangeRateService> logger,
            IOptions<ExchangeRateServiceOptions> options)
        {
            _httpClientFactory = httpClientFactory ?? throw new ArgumentNullException(nameof(httpClientFactory));
            _memoryCache = memoryCache ?? throw new ArgumentNullException(nameof(memoryCache));
            _logger = logger ?? throw new ArgumentNullException(nameof(logger));
            _options = options?.Value ?? throw new ArgumentNullException(nameof(options));
        }

        public async Task<decimal> GetExchangeRateAsync(string fromCurrency, string toCurrency)
        {
            string cacheKey = $"ExchangeRate_{fromCurrency}_{toCurrency}";

            // Try to get the exchange rate from cache
            if (_memoryCache.TryGetValue(cacheKey, out decimal cachedRate))
            {
                _logger.LogInformation($"Cache hit for exchange rate {fromCurrency} to {toCurrency}: {cachedRate}");
                return cachedRate;
            }

            _logger.LogInformation($"Cache miss for exchange rate {fromCurrency} to {toCurrency}, fetching from API");

            try
            {
                var client = _httpClientFactory.CreateClient("ExchangeRateApi");

                // Example URL for exchangeratesapi.io: 
                // /latest?base={fromCurrency}&symbols={toCurrency}&access_key={api_key}
                var response = await client.GetAsync(
                    $"/latest?base={fromCurrency}&symbols={toCurrency}&access_key={_options.ApiKey}");

                response.EnsureSuccessStatusCode();

                var content = await response.Content.ReadAsStringAsync();
                var rateResponse = JsonSerializer.Deserialize<ExchangeRateResponse>(content);

                if (rateResponse?.Success != true || 
                    !rateResponse.Rates.TryGetValue(toCurrency, out decimal rate))
                {
                    throw new ExchangeRateServiceException("Failed to parse exchange rate from response");
                }

                // Cache the exchange rate for 5 minutes
                _memoryCache.Set(cacheKey, rate, TimeSpan.FromMinutes(5));

                return rate;
            }
            catch (HttpRequestException ex)
            {
                _logger.LogError(ex, $"HTTP error while fetching exchange rate for {fromCurrency} to {toCurrency}");
                throw new ExchangeRateServiceException("Error connecting to exchange rate service", ex);
            }
            catch (JsonException ex)
            {
                _logger.LogError(ex, $"JSON parsing error for exchange rate {fromCurrency} to {toCurrency}");
                throw new ExchangeRateServiceException("Error parsing exchange rate response", ex);
            }
            catch (Exception ex) when (ex is not ExchangeRateServiceException)
            {
                _logger.LogError(ex, $"Unexpected error fetching exchange rate for {fromCurrency} to {toCurrency}");
                throw new ExchangeRateServiceException("Unexpected error fetching exchange rate", ex);
            }
        }

        private class ExchangeRateResponse
        {
            public bool Success { get; set; }
            public string Base { get; set; }
            public DateTime Date { get; set; }
            public Dictionary<string, decimal> Rates { get; set; }
        }
    }

    public class ExchangeRateServiceOptions
    {
        public string BaseUrl { get; set; }
        public string ApiKey { get; set; }
    }

    public class ExchangeRateServiceException : Exception
    {
        public ExchangeRateServiceException(string message) : base(message) { }
        public ExchangeRateServiceException(string message, Exception innerException) : base(message, innerException) { }
    }
}
