using System.Collections.Generic;
using Microsoft.Extensions.Options;

namespace CurrencyConversionService.Services
{
    public class ApiKeyValidator : IApiKeyValidator
    {
        private readonly HashSet<string> _validApiKeys;

        public ApiKeyValidator(IOptions<ApiKeyOptions> options)
        {
            _validApiKeys = new HashSet<string>(options.Value.ValidKeys);
        }

        public bool IsValid(string apiKey)
        {
            return !string.IsNullOrEmpty(apiKey) && _validApiKeys.Contains(apiKey);
        }
    }

    public class ApiKeyOptions
    {
        public List<string> ValidKeys { get; set; } = new List<string>();
    }
}
