using System;
using Microsoft.AspNetCore.Builder;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Polly;
using Polly.Extensions.Http;
using Microsoft.OpenApi.Models;
using System.IO;
using System.Reflection;
using CurrencyConversionService.Services;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container
builder.Services.AddControllers();

// Configure HttpClient for ExchangeRateApi with Polly
builder.Services.AddHttpClient("ExchangeRateApi", client =>
{
    var options = builder.Configuration.GetSection("ExchangeRateService").Get<ExchangeRateServiceOptions>();
    client.BaseAddress = new Uri(options.BaseUrl);
    client.DefaultRequestHeaders.Add("Accept", "application/json");
})
.AddPolicyHandler(GetRetryPolicy())
.AddPolicyHandler(GetCircuitBreakerPolicy());

// Configure caching
builder.Services.AddMemoryCache();

// Configure API key validation
builder.Services.Configure<ApiKeyOptions>(
    builder.Configuration.GetSection("ApiKeys"));
builder.Services.AddScoped<IApiKeyValidator, ApiKeyValidator>();

// Configure exchange rate service
builder.Services.Configure<ExchangeRateServiceOptions>(
    builder.Configuration.GetSection("ExchangeRateService"));
builder.Services.AddScoped<IExchangeRateService, ExchangeRateService>();

// Configure Swagger/OpenAPI
builder.Services.AddSwaggerGen(c =>
{
    c.SwaggerDoc("v1", new OpenApiInfo
    {
        Title = "Currency Conversion API",
        Version = "v1",
        Description = "A simple currency conversion API",
        Contact = new OpenApiContact
        {
            Name = "API Support",
            Email = "support@currencyapi.example.com"
        }
    });

    // Add security definition for API key
    c.AddSecurityDefinition("ApiKey", new OpenApiSecurityScheme
    {
