            _mockLogger = new Mock<ILogger<ConversionController>>();
            _mockApiKeyValidator = new Mock<IApiKeyValidator>();

            _controller = new ConversionController(
                _mockExchangeRateService.Object,
                _mockLogger.Object,
                _mockApiKeyValidator.Object
            );

            // Set up HttpContext for the controller
            var httpContext = new DefaultHttpContext();
            httpContext.Request.Headers["X-Api-Key"] = "valid-api-key";
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = httpContext
            };
        }

        [Fact]
        public async Task Convert_WithValidRequest_ReturnsOkResult()
        {
            // Arrange
            var request = new ConversionRequest
            {
                FromCurrency = "USD",
                ToCurrency = "EUR",
                Amount = 100m
            };

            _mockApiKeyValidator.Setup(v => v.IsValid(It.IsAny<string>())).Returns(true);
            _mockExchangeRateService.Setup(s => s.GetExchangeRateAsync("USD", "EUR"))
                .ReturnsAsync(0.85m);

            // Act
            var result = await _controller.Convert(request);

            // Assert
            var okResult = Assert.IsType<OkObjectResult>(result);
            var conversionResult = Assert.IsType<ConversionResult>(okResult.Value);
            Assert.Equal("USD", conversionResult.FromCurrency);
            Assert.Equal("EUR", conversionResult.ToCurrency);
            Assert.Equal(0.85m, conversionResult.ExchangeRate);
            Assert.Equal(100m, conversionResult.OriginalAmount);
            Assert.Equal(85m, conversionResult.ConvertedAmount);
        }

        [Fact]
        public async Task Convert_WithInvalidApiKey_ReturnsUnauthorized()
        {
            // Arrange
            var request = new ConversionRequest
            {
                FromCurrency = "USD",
                ToCurrency = "EUR",
                Amount = 100m
            };

            _mockApiKeyValidator.Setup(v => v.IsValid(It.IsAny<string>())).Returns(false);

            // Act
            var result = await _controller.Convert(request);

            // Assert
            var unauthorizedResult = Assert.IsType<UnauthorizedObjectResult>(result);
            var errorResponse = Assert.IsType<ErrorResponse>(unauthorizedResult.Value);
            Assert.Equal("Unauthorized", errorResponse.Error);
        }

        [Fact]
        public async Task Convert_WithServiceException_ReturnsServiceUnavailable()
        {
            // Arrange
            var request = new ConversionRequest
            {
                FromCurrency = "USD",
                ToCurrency = "EUR",
                Amount = 100m
            };

            _mockApiKeyValidator.Setup(v => v.IsValid(It.IsAny<string>())).Returns(true);
            _mockExchangeRateService.Setup(s => s.GetExchangeRateAsync("USD", "EUR"))
                .ThrowsAsync(new ExchangeRateServiceException("Service unavailable"));

