            Assert.Equal(StatusCodes.Status503ServiceUnavailable, statusCodeResult.StatusCode);
            var errorResponse = Assert.IsType<ErrorResponse>(statusCodeResult.Value);
            Assert.Equal("Rate service unavailable", errorResponse.Error);
        }
    }
