  // Find user by email
  static async findByEmail(email) {
    try {
      const [rows] = await db.execute(
        'SELECT * FROM users WHERE email = ?',
        [email]
      );
      return rows[0] || null;
    } catch (error) {
      throw error;
    }
  }

  // Find user by OAuth ID
  static async findByOAuthId(provider, providerId) {
    try {
      const [rows] = await db.execute(
        'SELECT * FROM users WHERE oauth_provider = ? AND oauth_id = ?',
        [provider, providerId]
      );
      return rows[0] || null;
    } catch (error) {
      throw error;
    }
  }

  // Create a new local user
  static async create(userData) {
    try {
      // Hash password
      const salt = await bcrypt.genSalt(10);
      const hashedPassword = await bcrypt.hash(userData.password, salt);

      const [result] = await db.execute(
        'INSERT INTO users (email, password, name, created_at) VALUES (?, ?, ?, NOW())',
        [userData.email, hashedPassword, userData.name]
      );

      const user = await this.findById(result.insertId);
      return user;
    } catch (error) {
      throw error;
    }
  }

  // Create a new OAuth user
  static async createOAuthUser(userData) {
    try {
      const [result] = await db.execute(
        'INSERT INTO users (email, name, oauth_provider, oauth_id, created_at) VALUES (?, ?, ?, ?, NOW())',
        [userData.email, userData.name, userData.provider, userData.providerId]
      );

      const user = await this.findById(result.insertId);
      return user;
    } catch (error) {
      throw error;
    }
  }
}

module.exports = User;
