const request = require('supertest');
const chai = require('chai');
const expect = chai.expect;
const app = require('../app');
const db = require('../config/database');

describe('Authentication Routes', () => {
  // Test user
  const testUser = {
    email: 'test@example.com',
    password: 'password123',
    name: 'Test User'
  };

  // Clean up after tests
  after(async () => {
    try {
      await db.execute('DELETE FROM users WHERE email = ?', [testUser.email]);
    } catch (error) {
      console.error('Error cleaning up test data:', error);
    }
  });

  describe('POST /auth/register', () => {
    it('should register a new user', async () => {
      const res = await request(app)
        .post('/auth/register')
        .send(testUser)
        .expect(201);

      expect(res.body).to.have.property('message', 'Registration successful');
      expect(res.body).to.have.property('user');
      expect(res.body.user).to.have.property('email', testUser.email);
    });

    it('should not register a user with an existing email', async () => {
      const res = await request(app)
        .post('/auth/register')
        .send(testUser)
        .expect(400);

      expect(res.body).to.have.property('message', 'User with this email already exists');
    });

    it('should validate input data', async () => {
      const res = await request(app)
        .post('/auth/register')
        .send({
          email: 'invalid-email',
          password: 'short',
          name: ''
        })
        .expect(400);

      expect(res.body).to.have.property('errors');
      expect(res.body.errors).to.be.an('array');
    });
  });

  describe('POST /auth/login', () => {
    it('should log in an existing user', async () => {
      const res = await request(app)
        .post('/auth/login')
        .send({
          email: testUser.email,
          password: testUser.password
        })
        .expect(200);

      expect(res.body).to.have.property('message', 'Login successful');
      expect(res.body).to.have.property('user');
      expect(res.body.user).to.have.property('email', testUser.email);
    });

    it('should not log in with incorrect credentials', async () => {
      const res = await request(app)
        .post('/auth/login')
        .send({
          email: testUser.email,
          password: 'wrongpassword'
        })
        .expect(401);
    });
  });

  describe('GET /user/profile', () => {
    let cookie;

    // Login before testing protected routes
    before(async () => {
      const res = await request(app)
        .post('/auth/login')
        .send({
          email: testUser.email,
          password: testUser.password
        });

      cookie = res.headers['set-cookie'];
    });

    it('should access protected route when authenticated', async () => {
      const res = await request(app)
        .get('/user/profile')
        .set('Cookie', cookie)
        .expect(200);

      expect(res.body).to.have.property('email', testUser.email);
      expect(res.body).to.have.property('name', testUser.name);
    });

    it('should not access protected route when not authenticated', async () => {
      const res = await request(app)
        .get('/user/profile')
        .expect(401);

      expect(res.body).to.have.property('message', 'Unauthorized');
    });
  });

  describe('GET /auth/logout', () => {
    let cookie;

    // Login before testing logout
    before(async () => {
      const res = await request(app)
        .post('/auth/login')
        .send({
          email: testUser.email,
          password: testUser.password
        });

      cookie = res.headers['set-cookie'];
    });

    it('should log out an authenticated user', async () => {
      const res = await request(app)
        .get('/auth/logout')
        .set('Cookie', cookie)
        .expect(200);

      expect(res.body).to.have.property('message', 'Logout successful');
    });
  });
});
